    category: 'Real Estate AI',
    tags: ['Real Estate', 'Property Management', 'AI Agents', 'PropTech'],
    hashtags: ['#RealEstateAI', '#PropTech', '#AIAgents', '#PropertyManagement', '#TenantExperience'],
